function check_transferOwnership_revokes_admin_role(address oldOwner, address newOwner) public {
    vm.assume(oldOwner != address(0) && newOwner != address(0) && oldOwner != newOwner);
    // Setup: oldOwner is current owner and has DEFAULT_ADMIN_ROLE
    vm.prank(oldOwner);
    contract.transferOwnership(newOwner);
    // After transfer, oldOwner should not have DEFAULT_ADMIN_ROLE
    assert(!contract.hasRole(contract.DEFAULT_ADMIN_ROLE(), oldOwner));
    // newOwner should have DEFAULT_ADMIN_ROLE
    assert(contract.hasRole(contract.DEFAULT_ADMIN_ROLE(), newOwner));
}
